7142	Value *TranslateLinAlgConvert(CallInst *CI, IntrinsicOp IOP, OP::OpCode OpCode,
7143	                              HLOperationLowerHelper &Helper,
7144	                              HLObjectOperationLowerHelper *ObjHelper,
7145	                              bool &Translated) {
7146	  hlsl::OP *HlslOp = &Helper.hlslOP;
7147	  IRBuilder<> Builder(CI);
7148	
7149	  Value *OutVecPtr = CI->getArgOperand(1);
7150	  DXASSERT_NOMSG(isa<PointerType>(OutVecPtr->getType()));
7151	  Type *OutVecTy = OutVecPtr->getType()->getPointerElementType();
7152	  Value *InVec = CI->getArgOperand(2);
7153	  Value *InInterp = CI->getArgOperand(3);
7154	  Value *OutInterp = CI->getArgOperand(4);
7155	
7156	  Constant *OpArg = HlslOp->GetU32Const((unsigned)OpCode);
7157	  Function *DxilFunc = HlslOp->GetOpFunc(OpCode, {OutVecTy, InVec->getType()});
7158	
7159	  Value *OutVec =
7160	      Builder.CreateCall(DxilFunc, {OpArg, InVec, InInterp, OutInterp});
7161	  Builder.CreateStore(OutVec, OutVecPtr);
7162	
7163	  return nullptr;
7164	}
