// REQUIRES: dxil-1-10
// RUN: %dxc -I %hlsl_headers -enable-16bit-types -T cs_6_10 %s | FileCheck %s

#include <dx/linalg.h>
using namespace dx::linalg;

typedef vector<half, 16> half16;
ByteAddressBuffer inbuf : register(t0);
RWByteAddressBuffer outbuf : register(u0);

[numthreads(1,1,1)]
void main() {
  half16 srcF16 = inbuf.Load<half16>(0);

  // CHECK: %[[LOAD:.*]] = call %dx.types.ResRet.v16f16 @dx.op.rawBufferVectorLoad.v16f16
  // CHECK: %[[VEC:.*]] = extractvalue %dx.types.ResRet.v16f16 %[[LOAD]], 0
  // CHECK-NOT: shufflevector <16 x half> %[[VEC]], <16 x half> undef, <4 x i32>
  // CHECK: call <4 x i32> @dx.op.linAlgConvert.v4i32.v16f16(i32 -2147483618, <16 x half> %[[VEC]], i32 8, i32 21)
  InterpretedVector<uint, 4, ComponentType::F8_E4M3FN> converted =
      Convert<ComponentType::F8_E4M3FN, ComponentType::F16>(srcF16);
  outbuf.Store<uint4>(0, converted.Data);
}

