Value *TranslateNodeGroupIncrementOutputCount(
    CallInst *CI, IntrinsicOp IOP, OP::OpCode op,
    HLOperationLowerHelper &helper, HLObjectOperationLowerHelper *pObjHelper,
    bool &Translated) {
