static bool IsHitObject3x4Getter(IntrinsicOp IOP) {
  switch (IOP) {
  default:
    return false;
  case IntrinsicOp::MOP_DxHitObject_GetObjectToWorld3x4:
  case IntrinsicOp::MOP_DxHitObject_GetWorldToObject3x4:
    return true;
  }
}

