Value *TranslateLinAlgConvert(CallInst *CI, IntrinsicOp IOP, OP::OpCode OpCode,
                              HLOperationLowerHelper &Helper,
                              HLObjectOperationLowerHelper *ObjHelper,
                              bool &Translated) {
  hlsl::OP *HlslOp = &Helper.hlslOP;
  IRBuilder<> Builder(CI);

  Value *OutVecPtr = CI->getArgOperand(1);
  DXASSERT_NOMSG(isa<PointerType>(OutVecPtr->getType()));
  Type *OutVecTy = OutVecPtr->getType()->getPointerElementType();
  Value *InVec = CI->getArgOperand(2);
  Value *InInterp = CI->getArgOperand(3);
  Value *OutInterp = CI->getArgOperand(4);

  // The intrinsic declaration uses the same special row/column size for the
  // output and input vectors so overload resolution can validate both operands
  // with the common numeric<> machinery.  Some linalg conversions intentionally
  // change the native vector width though (for example 16 f16 values pack into 4
  // i32 values when converting to fp8).  Sema therefore inserts an implicit
  // vector truncation/extension to make the input match the output vector size.
  // Strip that size-only cast here so the DXIL operation sees the full source
  // vector width; the op signature is allowed to have different input and output
  // vector sizes.
  if (CastInst *Cast = dyn_cast<CastInst>(InVec)) {
    Type *CastSrcTy = Cast->getOperand(0)->getType();
    Type *CastDstTy = Cast->getType();
    if (CastSrcTy->isVectorTy() && CastDstTy->isVectorTy() &&
        CastSrcTy->getVectorElementType() == CastDstTy->getVectorElementType())
      InVec = Cast->getOperand(0);
  } else if (ShuffleVectorInst *Shuffle = dyn_cast<ShuffleVectorInst>(InVec)) {
    Value *SrcVec = Shuffle->getOperand(0);
    Type *SrcTy = SrcVec->getType();
    Type *DstTy = Shuffle->getType();
    if (isa<UndefValue>(Shuffle->getOperand(1)) && SrcTy->isVectorTy() &&
        DstTy->isVectorTy() &&
        SrcTy->getVectorElementType() == DstTy->getVectorElementType()) {
      bool IsIdentityPrefix = true;
      unsigned NumMaskElements = DstTy->getVectorNumElements();
      for (unsigned I = 0; I != NumMaskElements; ++I) {
        int Mask = Shuffle->getMaskValue(I);
        if (Mask != (int)I) {
          IsIdentityPrefix = false;
          break;
        }
      }
      if (IsIdentityPrefix)
        InVec = SrcVec;
    }
  }

  Constant *OpArg = HlslOp->GetU32Const((unsigned)OpCode);
  Function *DxilFunc = HlslOp->GetOpFunc(OpCode, {OutVecTy, InVec->getType()});

  Value *OutVec =
      Builder.CreateCall(DxilFunc, {OpArg, InVec, InInterp, OutInterp});
  Builder.CreateStore(OutVec, OutVecPtr);

  return nullptr;
}

