// REQUIRES: dxil-1-10
// RUN: %dxc -I %hlsl_headers -T cs_6_10 -HV 202x -E main %s | FileCheck %s
// RUN: %dxc -I %hlsl_headers -T cs_6_10 -HV 202x -E main -fcgl %s | FileCheck %s --check-prefix=CHECK2
// RUN: %dxc -I %hlsl_headers -enable-16bit-types -T cs_6_10 -HV 202x -E convert_fp8 %s | FileCheck %s --check-prefix=PACKED

#include <dx/linalg.h>
using namespace dx::linalg;

ByteAddressBuffer inbuf : register(t0);
RWByteAddressBuffer outbuf : register(u0);

[numthreads(4,1,1)]
void main() {
  // CHECK-LABEL: define void @main()

  // CHECK: %{{.*}} = call <4 x i32> @dx.op.linAlgConvert.v4i32.v4f32
  // CHECK-SAME: (i32 -2147483618, <4 x float> <float 9.000000e+00, float 8.000000e+00, float 7.000000e+00, float 6.000000e+00>, i32 1, i32 2)
  // CHECK-SAME: ; LinAlgConvert(inputVector,inputInterpretation,outputInterpretation)

  // CHECK2: call void @"dx.hl.op..void (i32, <4 x i32>*, <4 x float>, i32, i32)"
  // CHECK2-SAME: (i32 422, <4 x i32>* %result, <4 x float> %{{.*}}, i32 1, i32 2)
  float4 vec = {9.0, 8.0, 7.0, 6.0};
  int4 result;
  __builtin_LinAlg_Convert(result, vec, 1, 2);
}

[numthreads(1,1,1)]
void convert_fp8() {
  // PACKED-LABEL: define void @convert_fp8()
  // PACKED: %[[LOAD:.*]] = call %dx.types.ResRet.v16f16 @dx.op.rawBufferVectorLoad.v16f16
  // PACKED: %[[VEC:.*]] = extractvalue %dx.types.ResRet.v16f16 %[[LOAD]], 0
  // PACKED-NOT: shufflevector <16 x half> %[[VEC]], <16 x half> undef, <4 x i32>
  // PACKED: call <4 x i32> @dx.op.linAlgConvert.v4i32.v16f16(i32 -2147483618, <16 x half> %[[VEC]], i32 8, i32 21)
  vector<half, 16> srcF16 = inbuf.Load<vector<half, 16> >(0);
  InterpretedVector<uint, 4, ComponentType::F8_E4M3FN> converted =
      Convert<ComponentType::F8_E4M3FN, ComponentType::F16>(srcF16);
  outbuf.Store<uint4>(0, converted.Data);
}

