diff --git a/lib/HLSL/HLOperationLower.cpp b/lib/HLSL/HLOperationLower.cpp
index abf0ad86..9cd9349b 100644
--- a/lib/HLSL/HLOperationLower.cpp
+++ b/lib/HLSL/HLOperationLower.cpp
@@ -7153,6 +7153,38 @@ Value *TranslateLinAlgConvert(CallInst *CI, IntrinsicOp IOP, OP::OpCode OpCode,
   Value *InInterp = CI->getArgOperand(3);
   Value *OutInterp = CI->getArgOperand(4);

+  // DXIL linAlgConvert allows the input and output vectors to have different
+  // native widths (for example 16 f16 values pack into 4 i32 values when
+  // converting to fp8).  Older intrinsic declarations used a common size for
+  // both operands, so strip any size-only cast that may already be present in
+  // the IR before this fix.
+  if (CastInst *Cast = dyn_cast<CastInst>(InVec)) {
+    Type *CastSrcTy = Cast->getOperand(0)->getType();
+    Type *CastDstTy = Cast->getType();
+    if (CastSrcTy->isVectorTy() && CastDstTy->isVectorTy() &&
+        CastSrcTy->getVectorElementType() == CastDstTy->getVectorElementType())
+      InVec = Cast->getOperand(0);
+  } else if (ShuffleVectorInst *Shuffle = dyn_cast<ShuffleVectorInst>(InVec)) {
+    Value *SrcVec = Shuffle->getOperand(0);
+    Type *SrcTy = SrcVec->getType();
+    Type *DstTy = Shuffle->getType();
+    if (isa<UndefValue>(Shuffle->getOperand(1)) && SrcTy->isVectorTy() &&
+        DstTy->isVectorTy() &&
+        SrcTy->getVectorElementType() == DstTy->getVectorElementType()) {
+      bool IsIdentityPrefix = true;
+      unsigned NumMaskElements = DstTy->getVectorNumElements();
+      for (unsigned I = 0; I != NumMaskElements; ++I) {
+        int Mask = Shuffle->getMaskValue(I);
+        if (Mask != (int)I) {
+          IsIdentityPrefix = false;
+          break;
+        }
+      }
+      if (IsIdentityPrefix)
+        InVec = SrcVec;
+    }
+  }
+
   Constant *OpArg = HlslOp->GetU32Const((unsigned)OpCode);
   Function *DxilFunc = HlslOp->GetOpFunc(OpCode, {OutVecTy, InVec->getType()});

diff --git a/tools/clang/lib/Headers/hlsl/dx/linalg.h b/tools/clang/lib/Headers/hlsl/dx/linalg.h
index 47743fa0..f4e73cb0 100644
--- a/tools/clang/lib/Headers/hlsl/dx/linalg.h
+++ b/tools/clang/lib/Headers/hlsl/dx/linalg.h
@@ -187,7 +187,8 @@ __MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::F64, double)

 template <ComponentEnum DstTy, ComponentEnum SrcTy, int SrcN> struct DstN {
   static const int Value =
-      (SrcN * ComponentTypeTraits<SrcTy>::ElementsPerScalar) /
+      (SrcN * ComponentTypeTraits<SrcTy>::ElementsPerScalar +
+       ComponentTypeTraits<DstTy>::ElementsPerScalar - 1) /
       ComponentTypeTraits<DstTy>::ElementsPerScalar;
 };

